            modelBuilder.Entity("CandidatesMS.Persistence.Entities.Mail", b =>
                {
                    b.Property<int>("MailId")
                        .ValueGeneratedOnAdd()
                        .HasColumnType("integer")
                        .HasAnnotation("Npgsql:ValueGenerationStrategy", NpgsqlValueGenerationStrategy.IdentityByDefaultColumn);

                    b.Property<int>("CandidateId")
                        .HasColumnType("integer");

                    b.Property<int>("CompanyUserId")
                        .HasColumnType("integer");

                    b.Property<string>("CreationDate")
                        .HasColumnType("text");

                    b.Property<string>("EmailMember")
                        .HasColumnType("text");

                    b.Property<string>("MailDescription")
                        .HasColumnType("text");

                    b.Property<int>("MailOwnerId")
                        .HasColumnType("integer");

                    b.Property<string>("MessageId")
                        .HasColumnType("text");

                    b.Property<string>("NameMemberUser")
                        .HasColumnType("text");

                    b.Property<string>("Subject")
                        .HasColumnType("text");

                    b.Property<string>("SurnameMemberUser")
                        .HasColumnType("text");

                    b.HasKey("MailId");

                    b.HasIndex("CandidateId");

